const attrs = { id: 'search', placeholder: 'Type…', autoFocus: true };

// These two are identical:
<input {...attrs} />
<input id="search" placeholder="Type…" autoFocus />

// PrimaryButton wraps <button> with a fixed visual style
function PrimaryButton(props) {
  return <button className="btn btn-primary" {...props} />;
}

// The spread goes AFTER className so the caller can override it:
// <PrimaryButton className="btn btn-primary btn-xl"> would work

// Callers can pass any native button attribute without the component
// knowing about them in advance:
<PrimaryButton type="submit" onClick={handleSubmit} disabled={isLoading}>
  Save
</PrimaryButton>

function TextInput({ label, error, className = '', ...inputProps }) {
  //                 ^     ^      ^               ^
  //            owned  owned  owned      forwarded to <input>
  return (
    <div className="field">
      {label && <label>{label}</label>}
      <input
        {...inputProps}                       // id, type, value, onChange, etc.
        className={`input ${error ? 'input--error' : ''} ${className}`.trim()}
        aria-invalid={error ? 'true' : undefined}
      />
      {error && <p className="error-msg">{error}</p>}
    </div>
  );
}

// Usage — component-specific and native props coexist cleanly:
<TextInput
  label="Email"
  error={errors.email}
  type="email"
  value={email}
  onChange={e => setEmail(e.target.value)}
  autoComplete="email"
/>

// Scenario A: Component wins (spread first, explicit last)
function EmailInput({ ...rest }) {
  return <input {...rest} type="email" />;
  //                      ^^^^^^^^^^^^
  //              Always email, caller cannot override type
}
<EmailInput type="text" />  // type is still 'email' — correct!

// Scenario B: Caller wins (explicit first, spread last)
function FlexibleInput({ type = 'text', ...rest }) {
  return <input type={type} {...rest} />;
  //                        ^^^^^^^^
  //              Spread after, so rest.type would override
  // Note: type is extracted above so it is NOT in rest
  // This is safe because type was destructured, not spread
}

// Scenario C: Bug — caller breaks the component
function BadEmail(props) {
  return <input type="email" {...props} />;
  //     ^^^^^^^^^^^^^      ^^^^^^^^^^^
  //   locked type          caller can override it!
}
<BadEmail type="password" />  // ❌ type is now 'password'

function ProfileForm({ user }) {
  // Build the shared base attrs once, reuse across multiple inputs
  const baseInputProps = {
    onChange: handleChange,
    disabled: !user.canEdit,
    autoComplete: 'off',
  };

  return (
    <form>
      <input {...baseInputProps} name="name" value={user.name} />
      <input {...baseInputProps} name="email" type="email" value={user.email} />
      <input {...baseInputProps} name="phone" type="tel" value={user.phone} />
    </form>
  );
}

const config = { children: 'From config', onClick: fn };

// JSX children override config.children
<Button {...config}>From JSX</Button>  // renders 'From JSX'

// No JSX children — config.children wins
<Button {...config} />                 // renders 'From config'

// Explicit children prop after spread also wins:
<Button {...config} children="Explicit" />  // renders 'Explicit'

import { ComponentPropsWithoutRef } from 'react';

// TextInput extends every prop <input> accepts, plus our own
type TextInputProps = ComponentPropsWithoutRef<'input'> & {
  label?: string;
  error?: string;
};

function TextInput({ label, error, className = '', ...rest }: TextInputProps) {
  return (
    <div>
      {label && <label>{label}</label>}
      <input
        {...rest}                        // TypeScript knows these are valid <input> attrs
        className={`input ${error ? 'input--error' : ''} ${className}`.trim()}
      />
      {error && <span role="alert">{error}</span>}
    </div>
  );
}

// Fully typed: TypeScript enforces correct attr names and value types
<TextInput label="Email" type="email" value={v} onChange={fn} maxLength={100} />

// 1. Template literal (simple, standard)
function Badge({ className = '', variant = 'default', ...rest }) {
  return (
    <span
      {...rest}
      className={`badge badge--${variant} ${className}`.trim()}
    />
  );
}

// 2. Array join (readable for many conditional classes)
function Badge({ className, variant = 'default', active = false, ...rest }) {
  const classes = [
    'badge',
    `badge--${variant}`,
    active && 'badge--active',
    className,
  ].filter(Boolean).join(' ');
  return <span {...rest} className={classes} />;
}

// 3. clsx / classnames library (most ergonomic at scale)
import clsx from 'clsx';
function Badge({ className, variant = 'default', active = false, ...rest }) {
  return (
    <span
      {...rest}
      className={clsx('badge', `badge--${variant}`, { 'badge--active': active }, className)}
    />
  );
}

function TrackedButton({ onClick, ...rest }) {
  function handleClick(e) {
    // Always track the click internally
    analytics.track('button_click', { label: rest['aria-label'] });
    // Then call the caller's handler if they provided one
    onClick?.(e);
  }

  return <button {...rest} onClick={handleClick} />;
  //                       ^^^^^^^^^^^^^^^^^^^^^^^
  //            Explicit onClick AFTER spread — component wins,
  //            but handleClick delegates to caller's onClick
}

// Caller's onClick still fires, plus tracking
<TrackedButton aria-label="save" onClick={save}>Save</TrackedButton>

const FORM_FIELDS = [
  { name: 'username', label: 'Username', type: 'text',     required: true  },
  { name: 'email',    label: 'Email',    type: 'email',    required: true  },
  { name: 'bio',      label: 'Bio',      type: 'textarea', required: false },
];

function AutoForm({ fields, values, onChange }) {
  return (
    <form>
      {fields.map(({ name, label, type, ...fieldProps }) => (
        <label key={name}>
          {label}
          {type === 'textarea'
            ? <textarea name={name} value={values[name]} onChange={onChange} {...fieldProps} />
            : <input    name={name} value={values[name]} onChange={onChange} type={type} {...fieldProps} />
          }
        </label>
      ))}
    </form>
  );
}

import { forwardRef } from 'react';

// Without forwardRef, ref is silently ignored
const TextInput = forwardRef(function TextInput({ label, ...rest }, ref) {
  return (
    <div>
      {label && <label>{label}</label>}
      <input ref={ref} {...rest} />
    </div>
  );
});

// Now the caller can hold a ref to the <input> DOM node
const inputRef = useRef(null);
<TextInput ref={inputRef} label="Search" type="search" />
// inputRef.current points to the <input> element

function AccessibleInput({ isRequired, ...rest }) {
  const requiredProps = isRequired
    ? { required: true, 'aria-required': 'true' }
    : {};

  return <input {...rest} {...requiredProps} />;
}

// Or inline with the logical AND short-circuit:
function AccessibleInput({ isRequired, ...rest }) {
  return (
    <input
      {...rest}
      {...(isRequired && { required: true, 'aria-required': 'true' })}
    />
  );
  // Note: short-circuit with && returns false when isRequired is false,
  // but spreading false/null/undefined is a no-op in JSX.
}

// A simple withLogging HOC
function withLogging(WrappedComponent, eventName) {
  return function LoggingWrapper({ onClick, ...rest }) {
    function handleClick(e) {
      console.log(`[${eventName}] clicked`);
      onClick?.(e);
    }
    // Spread rest so ALL props reach WrappedComponent:
    return <WrappedComponent {...rest} onClick={handleClick} />;
  };
}

const TrackedButton = withLogging(Button, 'primary-cta');

// Callers use TrackedButton exactly like Button:
<TrackedButton variant="primary" disabled={saving}>
  Save changes
</TrackedButton>

// Legacy pattern (pre-hooks, class-era React):
function Badge(props) {
  return <span className={`badge badge--${props.variant}`}>{props.children}</span>;
}
Badge.defaultProps = { variant: 'default' };

// This is now deprecated — React 18.3 warns about it.
// The modern equivalent:
function Badge({ variant = 'default', children }) {
  return <span className={`badge badge--${variant}`}>{children}</span>;
}

// When you need to spread defaults onto a native element,
// just set them in the destructuring — no static property needed:
function Button({ type = 'button', className = '', ...rest }) {
  return <button {...rest} type={type} className={`btn ${className}`.trim()} />;
}

import { ComponentPropsWithoutRef, forwardRef } from 'react';
import clsx from 'clsx';

type ButtonVariant = 'primary' | 'secondary' | 'ghost' | 'danger';
type ButtonSize = 'sm' | 'md' | 'lg';

type ButtonProps = ComponentPropsWithoutRef<'button'> & {
  variant?: ButtonVariant;
  size?: ButtonSize;
  isLoading?: boolean;
  leftIcon?: React.ReactNode;
  rightIcon?: React.ReactNode;
};

const Button = forwardRef<HTMLButtonElement, ButtonProps>(function Button(
  {
    variant = 'primary',
    size = 'md',
    isLoading = false,
    leftIcon,
    rightIcon,
    children,
    className,
    disabled,
    onClick,
    type = 'button',
    ...rest              // remaining native <button> attrs (aria-*, data-*, etc.)
  },
  ref
) {
  function handleClick(e: React.MouseEvent<HTMLButtonElement>) {
    if (isLoading) return;   // block clicks while loading
    onClick?.(e);            // delegate to caller
  }

  return (
    <button
      ref={ref}
      {...rest}              // native attrs first (caller's data-*, aria-*, etc.)
      type={type}            // explicit after rest — component controls type
      disabled={disabled || isLoading}
      onClick={handleClick}
      className={clsx(
        'btn',
        `btn--${variant}`,
        `btn--${size}`,
        { 'btn--loading': isLoading },
        className            // caller can add classes; comes last to override
      )}
      aria-busy={isLoading || undefined}
    >
      {isLoading && <span className="spinner" aria-hidden />}
      {leftIcon && <span className="btn__icon btn__icon--left">{leftIcon}</span>}
      {children}
      {rightIcon && <span className="btn__icon btn__icon--right">{rightIcon}</span>}
    </button>
  );
});

export default Button;
